/// Mint a token scoped to `(epic_id, phase, clone_path)` with the default TTL.
/// The returned [`CapabilityGuard`] revokes the token on drop.
pub fn mint(
    self: &Arc<Self>,
    epic_id: String,
    phase: String,
    clone_path: PathBuf,
) -> CapabilityGuard {
    self.mint_with_expiry(
        epic_id,
        phase,
        clone_path,
        now_ms() + CAPABILITY_TTL.as_millis() as i64,
    )
}

/// Mint with an explicit unix-ms expiry (used by tests to forge an expired
/// token). Otherwise identical to [`mint`](Self::mint).
pub(crate) fn mint_with_expiry(
    self: &Arc<Self>,
    epic_id: String,
    phase: String,
    clone_path: PathBuf,
    expires_at: i64,
) -> CapabilityGuard {
    let token = ulid::Ulid::new().to_string();
    let scope = CapabilityScope {
        epic_id,
        phase,
        clone_path,
        expires_at,
    };

